function solve(nums: number[], queries: number[][]): number[] {
    const ans: number[] = [];
    for (const [li, ri, threshold] of queries) {
        const freq = new Map<number, number>();
        let maxFreq = 0;
        let bestNum = -1;
        for (let i = li; i <= ri; i++) {
            const num = nums[i];
            const count = (freq.get(num) || 0) + 1;
            freq.set(num, count);
            if (count > maxFreq || (count === maxFreq && num < bestNum)) {
                maxFreq = count;
                bestNum = num;
            }
        }
        if (maxFreq >= threshold) {
            ans.push(bestNum);
        } else {
            ans.push(-1);
        }
    }
    return ans;
}

