use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut ans = Vec::new();
    for query in queries {
        let li = query[0] as usize;
        let ri = query[1] as usize;
        let threshold = query[2] as usize;
        let mut freq = HashMap::new();
        let mut max_freq = 0;
        let mut best_num = -1;
        for i in li..=ri {
            let num = nums[i];
            let count = freq.entry(num).or_insert(0);
            *count += 1;
            if *count > max_freq || (*count == max_freq && num < best_num) {
                max_freq = *count;
                best_num = num;
            }
        }
        if max_freq >= threshold {
            ans.push(best_num);
        } else {
            ans.push(-1);
        }
    }
    ans
}
```

